#include<bits/stdc++.h>
using namespace std;
vector<long long> a[1000010];
int main()
{
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        long long n,q;
        scanf("%lld%lld",&n,&q);
        for(long long i=1;i<=n;i++)
        {
            long long c;
            scanf("%lld",&c);
            a[i].clear();
            while(c--)
            {
                long long x;
                scanf("%lld",&x);
                a[i].push_back(x);
            }
            sort(a[i].begin(),a[i].end());
        }
        while(q--)
        {
            long long x,y;
            scanf("%lld%lld",&x,&y);
            long long u=a[x][(1ll*a[x].size()+1)/2-1],v=a[y][(1ll*a[y].size()+1)/2-1];
            long long pos=((long long)a[x].size()+(long long)a[y].size()+1)/2;
            long long l=min(u,v),r=max(u,v)+1,best=-1;
            while(l<=r)
            {
                long long mid=(l+r)>>1;
                long long cnt1=lower_bound(a[x].begin(),a[x].end(),mid-1)-a[x].begin();
                long long cnt2=lower_bound(a[y].begin(),a[y].end(),mid-1)-a[y].begin();
                if(cnt1+cnt2+1<=pos)
                {
                    best=mid;
                    l=mid+1;
                }
                else
                {
                    r=mid-1;
                }
            }
            long long ans=best;
            printf("%lld\n",ans-1);
        }
    }
    return 0;
}
